def backup_file(path: Path) -> None:
    if path.exists():
        BACKUP_DIR.mkdir(exist_ok=True)
        stamp = datetime.now().strftime("%Y%m%d_%H%M%S")
        shutil.copy2(path, BACKUP_DIR / f"{path.name}.{stamp}.bak")


def main() -> int:
    if not PARTIAL_PATH.exists():
        print(f"ERROR: missing {PARTIAL_PATH}")
        return 1
    if not CSS_PATH.exists():
        print(f"ERROR: missing {CSS_PATH}")
        return 1

    backup_file(PARTIAL_PATH)
    backup_file(CSS_PATH)

    PARTIAL_PATH.write_text(PARTIAL_CONTENT, encoding="utf-8")

    css_text = CSS_PATH.read_text(encoding="utf-8")
    if MARKER in css_text:
        print("SKIP: V181 CSS already exists")
    else:
        CSS_PATH.write_text(css_text.rstrip() + CSS_BLOCK + "\n", encoding="utf-8")
        print("DONE: V181 CSS added")

    report = f"""181_EXACT_SCREEN_STATS_BLOCK

Changed:
- {PARTIAL_PATH.relative_to(ROOT)}
- {CSS_PATH.relative_to(ROOT)}

Result:
- New stats block uses isolated pfb-stats-v181 classes.
- No old PNG stat icons are used.
- Layout: 3 cards top, 2 cards bottom centered.
- Hover tooltip: large number + label.
- Assists icon is boot-only inline SVG.

Backups:
- {BACKUP_DIR.relative_to(ROOT)}
"""
    REPORT_PATH.write_text(report, encoding="utf-8")
    print("DONE_181_EXACT_SCREEN_STATS_BLOCK")
    return 0

if __name__ == "__main__":
    raise SystemExit(main())
